Rule.Source:
import sailpoint.object.Filter;
 import sailpoint.object.Application;
import sailpoint.object.Identity;
import sailpoint.object.IdentityEntitlement;
import sailpoint.object.QueryOptions;
import sailpoint.tools.Util;
import sailpoint.api.Terminator;
import sailpoint.api.IdentityService;


Identity identity = null;
Application application = null;
IdentityService idService = new IdentityService(context);
boolean isLogicalBusiness = false;

try {
  identity = context.getObjectByName(Identity.class,"Aaron Wade");
  application = context.getObjectByName(Application.class,"ActiveDirectory");
  List adLinks = idService.	getLinks(identity, application);

  if(Util.nullSafeSize(adLinks)>0){

    Link link = adLinks.get(0);
    List entitlements = link.getAttribute("memberOf");

    if(Util.nullSafeSize(entitlements)>0){
      for(String entitlement : entitlements){

        Filter filter = Filter.eq("value",entitlement);
        ManagedAttribute ma = context.getUniqueObject(ManagedAttribute.class,filter);

        if(ma!=null){

          String logicalValue = ma.getAttribute("logicalBusinessAttribute");

          if(Util.nullSafeEq(logicalValue,"TRE-GIT")){
            isLogicalBusiness = true;
            break;
          }
        }
      }
    }
  }

} catch (Exception e) {
  log.error("Exception in Logical Business attribute Criteria assignment Rule : "+e.getMessage());
} finally{
  context.decache(application);
}

return isLogicalBusiness;









